using Microsoft.Extensions.Logging;

namespace MyMauiApp;

public static class MauiProgram
{
    public static MauiApp CreateMauiApp()
    {
        var builder = MauiApp.CreateBuilder();
        builder
            .UseMauiApp<App>()
            .ConfigureFonts(fonts =>
            {
                fonts.AddFont("OpenSans-Regular.ttf", "OpenSansRegular");
            });

        // --- Services ---
        // Singleton: one HttpClient and one DataService instance for the
        // entire app lifetime. This avoids socket exhaustion and lets
        // ViewModels share cached state / auth tokens.
        builder.Services.AddSingleton<HttpClient>();
        builder.Services.AddSingleton<IDataService, DataService>();

        // --- ViewModels ---
        // Transient: a fresh ViewModel every time a page is navigated to,
        // so stale data from a previous visit never leaks through.
        builder.Services.AddTransient<MainViewModel>();
        builder.Services.AddTransient<DetailViewModel>();

        // --- Pages ---
        // Transient: a new page instance per navigation, matching the
        // transient ViewModel it receives. Avoids UI state carry-over.
        builder.Services.AddTransient<MainPage>();
        builder.Services.AddTransient<DetailPage>();

#if DEBUG
        builder.Logging.AddDebug();
#endif

        return builder.Build();
    }
}

